from collections import deque
class Solution(object):
    def continuousSubarrays(self, nums):
        n = len(nums)
        ans = 0
        lo = 0
        max_dq = deque()
        min_dq = deque()
        for hi in range(n):
            while max_dq and nums[max_dq[-1]] <= nums[hi]:
                max_dq.pop()
            max_dq.append(hi)
            while min_dq and nums[min_dq[-1]] >= nums[hi]:
                min_dq.pop()
            min_dq.append(hi)
            while nums[max_dq[0]] - nums[min_dq[0]] > 2:
                lo += 1
                if max_dq[0] < lo: max_dq.popleft()
                if min_dq[0] < lo: min_dq.popleft()
            ans += hi - lo + 1
        return ans
